class Solution {
    public char kthCharacter(long k, int[] operations) {
        long len = 1;
        for (int op : operations) {
            if (op == 0) {
                len *= 2;
            } else {
                len = len * 2 - 1;
            }
        }
        long index = k % len;
        long temp = index;
        for (int i = operations.length - 1; i >= 0; i--) {
            if (operations[i] == 0) {
                index /= 2;
            } else {
                index = (index - 1) / 2;
            }
            if (index == 0) {
                break;
            }
        }
        char c = 'a';
        for (int i = 0; i < temp; i++) {
            if (operations[operations.length - 1 - i] == 0) {
                c = 'a';
            } else {
                c = (char) ((c - 'a' + 1) % 26 + 'a');
            }
        }
        return c;
    }
}
